    safe_locals = {'input_data': input_data}

    # Execute the transformation expression with the restricted context
    result = eval(transform_map_expr, safe_globals, safe_locals)

    # Validate that the result is a dictionary as required
    if not isinstance(result, dict):
        raise TypeError(
            f"Transformation expression must return a dict, got {type(result).__name__}"
